const topics = [
  'How AI chatbots handle 80% of customer questions automatically',
  'Managing WhatsApp, Instagram, Facebook and 5 more channels from one inbox',
  'How to never miss a lead with automated follow-ups',
  '24/7 appointment scheduling that works while you sleep',
  'How small businesses compete with big brands using automation',
  'Turn every customer conversation into data, insights, and sales',
  'The CRM built for businesses that sell through messaging apps',
  '5 ways AutoMarkIQ saves your team 10+ hours every week'
];

const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const week = Math.floor((now - startOfYear) / 604800000);
const isThursday = now.getDay() === 4;
const idx = (week * 2 + (isThursday ? 1 : 0)) % topics.length;

return [{ json: {
  topic: topics[idx],
  date: now.toISOString().split('T')[0]
} }];

const { topic, date } = $input.first().json;

const prompt = `You are a social media content creator for AutoMarkIQ, a multi-channel CRM platform built for small and medium businesses.

About AutoMarkIQ:
- Unifies all customer conversations in one inbox: WhatsApp, Instagram, Facebook, Messenger, Telegram, SMS, Email, and Live Chat
- AI-powered chatbots that handle customer queries automatically 24/7
- Full CRM: contact management, deal pipeline, and automated follow-ups
- Campaign builder for bulk messaging across all channels
- Appointment scheduling integrated into the communication flow
- Multi-agent team support with role-based access
- Built for businesses in any industry: retail, clinics, restaurants, logistics, services

Target audience: Small and medium business owners who want to save time, respond faster to customers, never miss a lead, and grow sales through better communication automation.

Tone: Professional, clear, results-focused. Inspiring and relatable, never salesy or corporate. Use numbers and concrete benefits when possible.
Language: English only.

Today's topic: ${topic}

Create 4 platform-optimized posts based on this topic. Return ONLY valid JSON with no markdown, no code fences, no extra explanation. Just the raw JSON object:
{
  "topic": "${topic}",
  "facebook": {
    "text": "<150-300 word post. Conversational and engaging. Tell a short story or ask a question. Include 3-5 relevant hashtags at the end separated by spaces.>"
  },
  "instagram": {
    "caption": "<150-200 word caption. Start with a hook line. Use relevant emojis naturally throughout. End with 10-15 hashtags on a new line.>"
  },
  "google_business": {
    "text": "<150-250 words. Informative and helpful. Focus on business value and local relevance. No hashtags. End with a soft call to action.>"
  },
  "youtube": {
    "title": "<Engaging video title, under 70 characters, with a keyword people would search>",
    "description": "<200-400 word video description. First 2 lines must hook the viewer. Include relevant keywords naturally. Add a call to action to visit automarkiq.com. End with relevant tags after a line break.>"
  }
}`;

return [{ json: {
  body: {
    model: 'claude-opus-4-7',
    max_tokens: 4096,
    messages: [{ role: 'user', content: prompt }]
  },
  topic,
  date
} }];

const raw = $input.first().json.content[0].text;
const topic = $('Build Prompt').first().json.topic;
const date = $('Build Prompt').first().json.date;

let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); }
    catch(e2) { throw new Error('Unparseable Claude response: ' + raw.substring(0, 300)); }
  } else {
    throw new Error('No JSON found in Claude response: ' + raw.substring(0, 300));
  }
}

return [{ json: { ...parsed, topic, date } }];
